def qp(a, b, MOD):
    x = 1
    a %= MOD
    while b:
        if b & 1:
            x = x * a % MOD
        a = a * a % MOD
        b >>= 1
    return x

def inv(a, MOD):
    return qp(a, MOD - 2, MOD)

def go(l, r, h, ts):
    if h <= 1 or l == r:
        ts.append(r - l + 1)
    else:
        m = l + r >> 1
        go(l, m, h - 1, ts)
        go(m + 1, r, h - 1, ts)

