def solve(n, k, MOD):
    invs = [0] * (n + 3)
    for i in range(1, max(n, 2) + 1):
        invs[i] = (invs[i - 1] + inv(i, MOD)) % MOD

    ts = []
    go(1, n, k, ts)
    
    cnt = {}
    ans = 0
    for x in ts:
        cnt[x] = cnt.get(x, 0) + 1
        ans += x * (x - 1) // 2
        ans %= MOD
        
    for t, count in cnt.items():
        if count >= 2:
            ans += calc(t, t, invs, MOD) * (count * (count - 1) // 2 % MOD)
            ans %= MOD
            
    for a, count_a in cnt.items():
        for b, count_b in cnt.items():
            if a < b:
                ans += calc(a, b, invs, MOD) * (count_a * count_b % MOD)
                ans %= MOD
                
    ans = ans * inv(2, MOD) % MOD
    ans = (ans % MOD + MOD) % MOD
    return ans

